class Solution:
    def latestDayToCross(self, row, col, cells):
        n = row * col
        def idx(r, c):
            return r * col + c
        def can(day):
            water = [[False] * col for _ in range(row)]
            for i in range(day):
                r, c = cells[i]
                water[r - 1][c - 1] = True
            parent = list(range(n + 2))
            TOP = n
            BOT = n + 1
            def find(x):
                while parent[x] != x:
                    parent[x] = parent[parent[x]]
                    x = parent[x]
                return x
            def union(a, b):
                ra, rb = find(a), find(b)
                if ra != rb:
                    parent[ra] = rb
            for r in range(row):
                for c in range(col):
                    if water[r][c]:
                        continue
                    cur = idx(r, c)
                    if r == 0:
                        union(cur, TOP)
                    if r == row - 1:
                        union(cur, BOT)
                    for dr, dc in ((1, 0), (0, 1)):
                        nr, nc = r + dr, c + dc
                        if 0 <= nr < row and 0 <= nc < col and not water[nr][nc]:
                            union(cur, idx(nr, nc))
            return find(TOP) == find(BOT)
        lo, hi = 0, n
        ans = 0
        while lo <= hi:
            mid = (lo + hi) // 2
            if can(mid):
                ans = mid
                lo = mid + 1
            else:
                hi = mid - 1
        return ans

