from collections import deque
class Solution:
    def latestDayToCross(self, row, col, cells):
        def can(day):
            grid = [[0] * col for _ in range(row)]
            for i in range(day):
                r, c = cells[i]
                grid[r - 1][c - 1] = 1
            q = deque()
            seen = [[False] * col for _ in range(row)]
            for c in range(col):
                if grid[0][c] == 0:
                    q.append((0, c))
                    seen[0][c] = True
            while q:
                r, c = q.popleft()
                if r == row - 1:
                    return True
                for dr, dc in ((1, 0), (-1, 0), (0, 1), (0, -1)):
                    nr, nc = r + dr, c + dc
                    if 0 <= nr < row and 0 <= nc < col and not seen[nr][nc] and grid[nr][nc] == 0:
                        seen[nr][nc] = True
                        q.append((nr, nc))
            return False
        lo, hi = 1, row * col
        ans = 0
        while lo <= hi:
            mid = (lo + hi) // 2
            if can(mid):
                ans = mid
                lo = mid + 1
            else:
                hi = mid - 1
        return ans

