var latestDayToCross = function(row, col, cells) {
    const can = (day) => {
        const grid = Array.from({length: row}, () => new Array(col).fill(0));
        for (let i = 0; i < day; i++) {
            const [r, c] = cells[i];
            grid[r - 1][c - 1] = 1;
        }
        const seen = Array.from({length: row}, () => new Array(col).fill(false));
        let q = [];
        for (let c = 0; c < col; c++) {
            if (grid[0][c] === 0) { q.push([0, c]); seen[0][c] = true; }
        }
        const dirs = [[1, 0], [-1, 0], [0, 1], [0, -1]];
        let head = 0;
        while (head < q.length) {
            const [r, c] = q[head++];
            if (r === row - 1) return true;
            for (const [dr, dc] of dirs) {
                const nr = r + dr, nc = c + dc;
                if (nr >= 0 && nr < row && nc >= 0 && nc < col && !seen[nr][nc] && grid[nr][nc] === 0) {
                    seen[nr][nc] = true;
                    q.push([nr, nc]);
                }
            }
        }
        return false;
    };
    let lo = 1, hi = row * col, ans = 0;
    while (lo <= hi) {
        const mid = (lo + hi) >> 1;
        if (can(mid)) { ans = mid; lo = mid + 1; }
        else hi = mid - 1;
    }
    return ans;
};
